def find_by_number(raqam):
    try:
        r = int(raqam)
        for c in CONTRACTS:
            if c["raqam"] == r:
                return c
    except:
        pass
    return None

def find_by_name(name):
    name = name.strip().upper()
    return [c for c in CONTRACTS if name in c["korxona"].upper()][:5]

def find_by_inn(inn):
    inn = inn.strip()
    for c in CONTRACTS:
        if c["inn"] == inn:
            return c
    return None

def gen_num():
    return random.randint(10000, 99999)

(LANG, MENU, COMP_ADDR,
 APP_TYPE, APP_NUM, APP_NAME, APP_INN,
 APP_SELECT, APP_CONFIRM, APP_DATE, APP_VOLUME) = range(11)

def lang_kb():
    return ReplyKeyboardMarkup(
        [["O'zbek", "Русский", "English"]],
        resize_keyboard=True
    )

def menu_kb(lang):
    btns = {
        "uz": [["Shikoyat", "Yuridik shaxs zaявkasi"]],
        "ru": [["Жалоба", "Заявка юр. лица"]],
        "en": [["Complaint", "Legal Entity Application"]],
    }
    return ReplyKeyboardMarkup(btns[lang], resize_keyboard=True)

def search_kb(lang):
    btns = {
        "uz": [["Shartnoma raqami"], ["Korxona nomi"], ["INN raqami"], ["Orqaga"]],
        "ru": [["Номер договора"], ["Название организации"], ["ИНН"], ["Назад"]],
        "en": [["Contract number"], ["Organization name"], ["Tax ID (INN)"], ["Back"]],
    }
    return ReplyKeyboardMarkup(btns[lang], resize_keyboard=True)

def yn_kb(lang):
    btns = {
        "uz": [["Ha, zaявka beraman", "Yoq"]],
        "ru": [["Da, podat zayavku", "Net"]],
        "en": [["Yes, submit application", "No"]],
    }
    return ReplyKeyboardMarkup(btns[lang], resize_keyboard=True)

def contract_info(c, lang):
    oylik = f"{c['oylik']:,}".replace(",", " ")
    if lang == "uz":
        return (
            "Shartnoma topildi!\n\n"
            f"Korxona: {c['korxona']}\n"
            f"Shartnoma: {c['raqam']}\n"
            f"Tel: {c['tel'] or '-'}\n"
            f"Oylik summa: {oylik} som\n"
            f"Inspektor: {c['inspektor'] or '-'}\n\n"
            "Zaявka berishni xohlaysizmi?"
        )
    elif lang == "ru":
        return (
            "Dogovor najden!\n\n"
            f"Organizatsiya: {c['korxona']}\n"
            f"Dogovor: {c['raqam']}\n"
            f"Tel: {c['tel'] or '-'}\n"
            f"Ezhemesyachno: {oylik} sum\n"
            f"Inspektor: {c['inspektor'] or '-'}\n\n"
            "Xotite podat zayavku?"
        )
    else:
        return (
            "Contract found!\n\n"
            f"Organization: {c['korxona']}\n"
            f"Contract: {c['raqam']}\n"
            f"Tel: {c['tel'] or '-'}\n"
            f"Monthly: {oylik} UZS\n"
            f"Inspector: {c['inspektor'] or '-'}\n\n"
            "Would you like to submit an application?"
        )

async def start(update: Update, ctx: ContextTypes.DEFAULT_TYPE):
    ctx.user_data.clear()
    await update.message.reply_text(
        "Assalomu alaykum! / Dobro pozhalovat! / Welcome!\n\nBioTechnoEko\n\nTilni tanlang / Viberite yazyk / Select language:",
        reply_markup=lang_kb()
    )
    return LANG

async def set_lang(update: Update, ctx: ContextTypes.DEFAULT_TYPE):
    text = update.message.text
    if "zbek" in text: lang = "uz"
    elif "усский" in text or "Rus" in text: lang = "ru"
    elif "nglish" in text: lang = "en"
    else:
        await update.message.reply_text("Iltimos tanlang:", reply_markup=lang_kb())
        return LANG
    ctx.user_data["lang"] = lang
    msgs = {
        "uz": "Asosiy menyu. Xizmat turini tanlang:",
        "ru": "Glavnoe menyu. Viberite uslugu:",
        "en": "Main menu. Select a service:",
    }
    await update.message.reply_text(msgs[lang], reply_markup=menu_kb(lang))
    return MENU

async def menu_handler(update: Update, ctx: ContextTypes.DEFAULT_TYPE):
    lang = ctx.user_data.get("lang", "uz")
    text = update.message.text
    if any(w in text for w in ["Shikoyat", "Жалоба", "Complaint"]):
        msgs = {
            "uz": "Shikoyatingizni qabul qilish uchun manzilingizni yuboring (kocha, uy raqami):",
            "ru": "Dlya podachi zhalobi otpravte vash adres (ulitsa, nomer doma):",
            "en": "To submit a complaint, please send your address (street, house number):",
        }
        await update.message.reply_text(msgs[lang], reply_markup=ReplyKeyboardRemove())
        return COMP_ADDR
    elif any(w in text for w in ["Yuridik", "Заявка", "Legal"]):
        msgs = {
            "uz": "Shartnomangizni qanday topamiz?",
            "ru": "Kak najdem vash dogovor?",
            "en": "How would you like to find your contract?",
        }
        await update.message.reply_text(msgs[lang], reply_markup=search_kb(lang))
        return APP_TYPE
    await update.message.reply_text("...", reply_markup=menu_kb(lang))
    return MENU

async def complaint_addr(update: Update, ctx: ContextTypes.DEFAULT_TYPE):
    lang = ctx.user_data.get("lang", "uz")
    addr = update.message.text
    num = gen_num()
    u = update.message.from_user
    uname = u.username if u.username else "noma'lum"
    disp_msg = (
        f"YANGI SHIKOYAT #{num}\n"
        f"Foydalanuvchi: {u.full_name}\n"
        f"Telegram: @{uname} | ID: {u.id}\n"
        f"Manzil: {addr}\n"
        f"Til: {lang.upper()}"
    )
    try:
        await ctx.bot.send_message(chat_id=DISPATCHER, text=disp_msg)
    except Exception as e:
        logger.error(f"Dispatcher xato: {e}")
    msgs = {
        "uz": f"Shikoyatingiz qabul qilindi!\nShikoyat raqami: #{num}\n\nTez orada hal qilinadi!\nDispatcher: {DISPATCHER}",
        "ru": f"Vasha zhaloba prinyata!\nNomer zhalobi: #{num}\n\nBudet resheno v blizhayshee vremya!\nDispetcher: {DISPATCHER}",
        "en": f"Your complaint has been received!\nComplaint number: #{num}\n\nIt will be resolved soon!\nDispatcher: {DISPATCHER}",
    }
    await update.message.reply_text(msgs[lang], reply_markup=menu_kb(lang))
    return MENU

async def app_type(update: Update, ctx: ContextTypes.DEFAULT_TYPE):
    lang = ctx.user_data.get("lang", "uz")
    text = update.message.text
    if any(w in text for w in ["Orqaga", "Назад", "Back"]):
        msgs = {"uz": "Asosiy menyu:", "ru": "Glavnoe menyu:", "en": "Main menu:"}
        await update.message.reply_text(msgs[lang], reply_markup=menu_kb(lang))
        return MENU
    elif any(w in text for w in ["raqami", "Номер", "number"]):
        msgs = {"uz": "Shartnoma raqamingizni yuboring:", "ru": "Otpravte nomer vashego dogovora:", "en": "Please send your contract number:"}
        await update.message.reply_text(msgs[lang], reply_markup=ReplyKeyboardRemove())
        return APP_NUM
    elif any(w in text for w in ["nomi", "Название", "name"]):
        msgs = {"uz": "Korxona nomingizni yuboring:", "ru": "Otpravte nazvanie vashey organizatsii:", "en": "Please send your organization name:"}
        await update.message.reply_text(msgs[lang], reply_markup=ReplyKeyboardRemove())
        return APP_NAME
    elif any(w in text for w in ["INN", "ИНН", "Tax"]):
        msgs = {"uz": "INN raqamingizni yuboring:", "ru": "Otpravte vash INN:", "en": "Please send your Tax ID (INN):"}
        await update.message.reply_text(msgs[lang], reply_markup=ReplyKeyboardRemove())
        return APP_INN
    await update.message.reply_text("...", reply_markup=search_kb(lang))
    return APP_TYPE

async def app_by_num(update: Update, ctx: ContextTypes.DEFAULT_TYPE):
    lang = ctx.user_data.get("lang", "uz")
    c = find_by_number(update.message.text)
    if c:
        ctx.user_data["contract"] = c
        await update.message.reply_text(contract_info(c, lang), reply_markup=yn_kb(lang))
        return APP_CONFIRM
    msgs = {
        "uz": f"Shartnoma topilmadi. Boshqa usulni sinab koring yoki dispatcher: {DISPATCHER}",
        "ru": f"Dogovor ne najden. Poprobujte drugoy sposob ili dispatcher: {DISPATCHER}",
        "en": f"Contract not found. Try another method or contact dispatcher: {DISPATCHER}",
    }
    await update.message.reply_text(msgs[lang], reply_markup=search_kb(lang))
    return APP_TYPE

async def app_by_name(update: Update, ctx: ContextTypes.DEFAULT_TYPE):
    lang = ctx.user_data.get("lang", "uz")
    results = find_by_name(update.message.text)
    if not results:
        msgs = {
            "uz": f"Topilmadi. Dispatcher: {DISPATCHER}",
            "ru": f"Ne najdeno. Dispetcher: {DISPATCHER}",
            "en": f"Not found. Dispatcher: {DISPATCHER}",
        }
        await update.message.reply_text(msgs[lang], reply_markup=search_kb(lang))
        return APP_TYPE
    if len(results) == 1:
        ctx.user_data["contract"] = results[0]
        await update.message.reply_text(contract_info(results[0], lang), reply_markup=yn_kb(lang))
        return APP_CONFIRM
    ctx.user_data["results"] = results
    msgs = {"uz": "Bir nechta natija. Raqam yuboring:", "ru": "Neskolko rezultatov. Otpravte nomer:", "en": "Multiple results. Send the number:"}
    text = msgs[lang] + "\n\n"
    for i, r in enumerate(results, 1):
        text += f"{i}. {r['korxona']} (N{r['raqam']})\n"
    await update.message.reply_text(text, reply_markup=ReplyKeyboardRemove())
    return APP_SELECT

async def app_by_inn(update: Update, ctx: ContextTypes.DEFAULT_TYPE):
    lang = ctx.user_data.get("lang", "uz")
    c = find_by_inn(update.message.text)
    if c:
        ctx.user_data["contract"] = c
        await update.message.reply_text(contract_info(c, lang), reply_markup=yn_kb(lang))
        return APP_CONFIRM
    msgs = {
        "uz": f"Topilmadi. Dispatcher: {DISPATCHER}",
        "ru": f"Ne najdeno. Dispetcher: {DISPATCHER}",
        "en": f"Not found. Dispatcher: {DISPATCHER}",
    }
    await update.message.reply_text(msgs[lang], reply_markup=search_kb(lang))
    return APP_TYPE

async def app_select(update: Update, ctx: ContextTypes.DEFAULT_TYPE):
    lang = ctx.user_data.get("lang", "uz")
    results = ctx.user_data.get("results", [])
    try:
        c = results[int(update.message.text) - 1]
        ctx.user_data["contract"] = c
        await update.message.reply_text(contract_info(c, lang), reply_markup=yn_kb(lang))
        return APP_CONFIRM
    except:
        await update.message.reply_text("Raqam yuboring (1, 2, ...):")
        return APP_SELECT

async def app_confirm(update: Update, ctx: ContextTypes.DEFAULT_TYPE):
    lang = ctx.user_data.get("lang", "uz")
    text = update.message.text
    if any(w in text for w in ["Ha", "Da", "Yes"]):
        msgs = {
            "uz": "Chiqindi olib ketish sanasi va vaqtini yuboring:\n(Masalan: 25-may, soat 10:00)",
            "ru": "Otpravte datu i vremya vivoza musora:\n(Naprimer: 25 maya, v 10:00)",
            "en": "Send the date and time for waste collection:\n(Example: May 25, 10:00 AM)",
        }
        await update.message.reply_text(msgs[lang], reply_markup=ReplyKeyboardRemove())
        return APP_DATE
    msgs = {"uz": "Asosiy menyu:", "ru": "Glavnoe menyu:", "en": "Main menu:"}
    await update.message.reply_text(msgs[lang], reply_markup=menu_kb(lang))
    return MENU

async def app_date(update: Update, ctx: ContextTypes.DEFAULT_TYPE):
    lang = ctx.user_data.get("lang", "uz")
    ctx.user_data["date"] = update.message.text
    msgs = {
        "uz": "Chiqindi hajmini yuboring (m3 yoki kg):",
        "ru": "Otpravte obyom musora (m3 ili kg):",
        "en": "Send the waste volume (m3 or kg):",
    }
    await update.message.reply_text(msgs[lang], reply_markup=ReplyKeyboardRemove())
    return APP_VOLUME

async def app_volume(update: Update, ctx: ContextTypes.DEFAULT_TYPE):
    lang = ctx.user_data.get("lang", "uz")
    volume = update.message.text
    date = ctx.user_data.get("date", "-")
    c = ctx.user_data.get("contract", {})
    num = gen_num()
    u = update.message.from_user
    uname = u.username if u.username else "noma'lum"
    disp_msg = (
        f"YANGI ZAЯВKA #{num}\n"
        f"Korxona: {c.get('korxona', '?')}\n"
        f"Shartnoma: {c.get('raqam', '?')}\n"
        f"INN: {c.get('inn', '?')}\n"
        f"Tel: {c.get('tel', '?')}\n"
        f"Inspektor: {c.get('inspektor', '?')}\n"
        f"Sana/Vaqt: {date}\n"
        f"Hajm: {volume}\n"
        f"Foydalanuvchi: {u.full_name} (@{uname})\n"
        f"Til: {lang.upper()}"
    )
    try:
        await ctx.bot.send_message(chat_id=DISPATCHER, text=disp_msg)
    except Exception as e:
        logger.error(f"Dispatcher xato: {e}")
    msgs = {
        "uz": f"Zaявkangiz qabul qilindi!\nZaявka: #{num}\nKorxona: {c.get('korxona','?')}\nSana: {date}\nHajm: {volume}\n\nDispatcher: {DISPATCHER}",
        "ru": f"Vasha zayavka prinyata!\nZayavka: #{num}\nOrganizatsiya: {c.get('korxona','?')}\nData: {date}\nObyom: {volume}\n\nDispetcher: {DISPATCHER}",
        "en": f"Your application is accepted!\nApplication: #{num}\nOrganization: {c.get('korxona','?')}\nDate: {date}\nVolume: {volume}\n\nDispatcher: {DISPATCHER}",
    }
    await update.message.reply_text(msgs[lang], reply_markup=menu_kb(lang))
    return MENU

async def cancel(update: Update, ctx: ContextTypes.DEFAULT_TYPE):
    await update.message.reply_text("Bekor qilindi. /start", reply_markup=ReplyKeyboardRemove())
    return ConversationHandler.END

def main():
    app = Application.builder().token(BOT_TOKEN).build()
    conv = ConversationHandler(
        entry_points=[CommandHandler("start", start)],
        states={
            LANG:        [MessageHandler(filters.TEXT & ~filters.COMMAND, set_lang)],
            MENU:        [MessageHandler(filters.TEXT & ~filters.COMMAND, menu_handler)],
            COMP_ADDR:   [MessageHandler(filters.TEXT & ~filters.COMMAND, complaint_addr)],
            APP_TYPE:    [MessageHandler(filters.TEXT & ~filters.COMMAND, app_type)],
            APP_NUM:     [MessageHandler(filters.TEXT & ~filters.COMMAND, app_by_num)],
            APP_NAME:    [MessageHandler(filters.TEXT & ~filters.COMMAND, app_by_name)],
            APP_INN:     [MessageHandler(filters.TEXT & ~filters.COMMAND, app_by_inn)],
            APP_SELECT:  [MessageHandler(filters.TEXT & ~filters.COMMAND, app_select)],
            APP_CONFIRM: [MessageHandler(filters.TEXT & ~filters.COMMAND, app_confirm)],
            APP_DATE:    [MessageHandler(filters.TEXT & ~filters.COMMAND, app_date)],
            APP_VOLUME:  [MessageHandler(filters.TEXT & ~filters.COMMAND, app_volume)],
        },
        fallbacks=[CommandHandler("cancel", cancel), CommandHandler("start", start)],
        allow_reentry=True,
    )
    app.add_handler(conv)
    print("BioTechnoEko bot ishga tushdi!")
    app.run_polling()

if __name__ == "__main__":
    main()
